mapper.update:
update pr_import_history a
    left join pr_house b on a.room_num = b.room_num and a.org_name = b.org_name
set a.house_id = b.id, a.org_id = b.org_id
where a.company_id = #{companyId} and a.type = '0' and a.create_by = #{create}
  and b.company_id = #{companyId}

mapper.select:
select * from pr_import_history
where company_id = #{companyId} and type = '0' and create_by = #{create}
  and (house_id is null or org_id is null) limit 500
